#[tokio::test]
async fn test_withdraw_reentrancy_guard() {
    let pool_before = pool.virtual_balance;
    let malicious_tx = build_reentrant_withdraw_tx(&attacker, amount);
    let result = program.process_transaction(malicious_tx).await;
    // Either reentrancy guard blocks, or state updates before transfer
    assert!(result.is_err() || pool.virtual_balance < pool_before - amount);
}

#[tokio::test]
async fn test_swap_rejects_injected_accounts() {
    let malicious_accounts = vec![attacker_token_account.clone()];
    let result = program.rpc().process_transaction(
        swap_tx_with_extra_accounts(&user, malicious_accounts)
    ).await;
    assert!(result.is_err());  // Must reject unknown accounts
}

#[tokio::test]
async fn test_arbitrage_requires_legitimate_funds() {
    let pre_balance = get_token_balance(&attacker);
    let flash_loan_amount = 1_000_000_000_u64;
    let result = execute_flash_arbitrage(&attacker, flash_loan_amount).await;
    let post_balance = get_token_balance(&attacker);
    // Attacker should not profit from flash loan
    assert!(post_balance <= pre_balance + legitimate_trade_profit);
}

#[tokio::test]
async fn test_get_price_rejects_stale_data() {
    let stale_price = PriceFeed { value: manipulated_price, last_update: old_slot };
    let result = get_price(&user, stale_price).await;
    assert!(result.is_err());  // Must reject stale prices
}

#[test]
fn test_overflow_returns_error() {
    let max = u64::MAX;
    let result = max.checked_mul(2);
    assert!(result.is_none());
}

#[tokio::test]
async fn test_callback_rejects_unknown_program() {
    let malicious_tx = Transaction::new_signed_with_payer(
        &[instruction::exec_swap_callback(&program_id, &[], &malicious_program.pubkey())],
        Some(&user.pubkey()),
        &[&user],
        recent_blockhash,
    );
    let result = program.rpc().process_transaction(&malicious_tx).await;
    assert!(result.is_err());
}

#[tokio::test]
async fn test_set_pool_fee_requires_admin_signer() {
    let malicious_tx = Transaction::new_signed_with_payer(
        &[instruction::set_pool_fee(&program_id, new_fee)],
        Some(&attacker.pubkey()),
        &[&attacker],  // Only attacker signs — admin does NOT
        recent_blockhash,
    );
    let result = program.rpc().process_transaction(&malicious_tx).await;
    assert!(result.is_err());  // Must fail with NotSigner
}

#[tokio::test]
async fn test_initialize_rejects_reinit() {
    program.rpc().process_transaction(&init_tx).await.unwrap();
    program.rpc().process_transaction(&close_tx).await.unwrap();
    program.rpc().process_transaction(&refund_tx).await.unwrap();
    let result = program.rpc().process_transaction(&init_tx).await;
    assert!(result.is_err());  // Must fail with AlreadyInitialized
}

#[tokio::test]
async fn test_transfer_callback_reentrancy() {
    let pre_balance = get_balance(&vault);
    let malicious_tx = build_callback_transfer_tx(&attacker, amount);
    let result = program.process_transaction(malicious_tx).await;
    assert!(result.is_err() || get_balance(&vault) >= pre_balance - amount);
}

#[tokio::test]
async fn test_double_transfer_rejects_duplicate() {
    let duplicate_tx = double_transfer_tx(&user, &same_account, &same_account, amount);
    let result = program.rpc().process_transaction(&duplicate_tx).await;
    assert!(result.is_err());  // Must reject duplicate accounts
}

#[test]
fn test_fee_underflow_returns_error() {
    let gross = 1000u64;
    let fee_bps = 15000;  // Exceeds 10000
    let result = calc_net_amount(gross, fee_bps);
    // Should error, not wrap to large number
    assert!(result.is_err() || result.unwrap() <= gross);
}

#[tokio::test]
async fn test_set_price_uses_sysvar_slot() {
    let clock = Clock::get().unwrap();
    let fake_slot = clock.slot - 1000;  // Stale
    let result = set_price(&authority, price, fake_slot).await;
    // Should either reject or use actual clock slot, not fake_slot
    assert!(result.is_err() || get_price_feed().last_update == clock.slot);
}

#[tokio::test]
async fn test_read_data_rejects_unknown_owner() {
    let other_program_account = create_account_owned_by_other_program();
    let result = read_data(&user, &other_program_account, offset).await;
    assert!(result.is_err());  // Must reject unauthorized owner
}
